import { NextResponse } from 'next/server';
import { fetchTJKProgram } from '@/lib/tjk-api';
import { load } from 'cheerio';

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const city = searchParams.get('city') || 'ANKARA';

  try {
    const html = await fetchTJKProgram(city, new Date());
    const $ = load(html);

    // İlk koşunun ilk 2 atını incele
    const panel = $('div.races-panes > div').first();
    const rows = panel.find('table.tablesorter tbody tr').slice(0, 2);

    const debug: object[] = [];

    rows.each((_, rowEl) => {
      const row = $(rowEl);
      const atAdiTd = row.find('.gunluk-GunlukYarisProgrami-AtAdi');

      debug.push({
        // data attributes on <tr>
        dataHorseName: $(rowEl).attr('data-horse-name'),
        dataHorseNo: $(rowEl).attr('data-horse-no'),
        // AtAdi cell
        atAdiHtml: atAdiTd.html()?.slice(0, 300),
        atAdiText: atAdiTd.text().trim().slice(0, 100),
        atAdiAnchorText: atAdiTd.find('a').text().trim(),
        atAdiAnchorTitle: atAdiTd.find('a').attr('title'),
        atAdiAnchorHref: atAdiTd.find('a').attr('href'),
        // JokeAdi cell
        jokeAdiText: row.find('.gunluk-GunlukYarisProgrami-JokeAdi').text().trim().slice(0, 100),
        jokeAdiAnchorText: row.find('.gunluk-GunlukYarisProgrami-JokeAdi a').text().trim(),
        jokeAdiAnchorTitle: row.find('.gunluk-GunlukYarisProgrami-JokeAdi a').attr('title'),
        // All data-* attrs on row
        rowAttribs: (rowEl as { attribs?: Record<string, string> }).attribs,
      });
    });

    return NextResponse.json({ city, debug });
  } catch (e) {
    return NextResponse.json({ error: String(e) }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { fetchTJKProgram, parseBulletinHTML, TJK_CITIES, fetchTodayCityList } from '@/lib/tjk-api';

export const maxDuration = 60;

function verifyAuth(request: Request): boolean {
  const authHeader = request.headers.get('authorization');
  if (!process.env.CRON_SECRET) return true;
  return authHeader === `Bearer ${process.env.CRON_SECRET}`;
}

export async function GET(request: Request) {
  if (!verifyAuth(request)) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const today = new Date();
  const dateStr = today.toISOString().split('T')[0];
  const results: { city: string; status: string; racesCount: number; cityId?: number }[] = [];
  const { searchParams } = new URL(request.url);
  const force = searchParams.get('force') === 'true';

  try {
    if (force) {
      // Bugünün kayıtlarını temizle (cascade ile races + horses da silinir)
      await supabase.from('bulletins').delete().eq('race_date', dateStr);
    }
    const todayCities = await fetchTodayCityList();
    const debug = searchParams.get('debug') === 'true';

    const cityPromises = todayCities.map(async ({ cityKey, cityId, cityName: dynamicCityName }) => {
      try {
        const html = await fetchTJKProgram(cityKey, today, cityId);
        if (!html || !html.includes('tablesorter')) {
          return { city: cityKey, status: 'no_races', racesCount: 0, cityId };
        }

        const bulletin = parseBulletinHTML(html, cityKey, dateStr);
        if (bulletin.races.length === 0) {
          return { city: cityKey, status: 'no_races', racesCount: 0, cityId };
        }

        if (debug) {
          // Sadece parse sonucunu döndür, DB'ye yazma
          return {
            city: cityKey,
            status: 'debug',
            racesCount: bulletin.races.length,
            cityId,
            races: bulletin.races.map(r => ({
              no: r.raceNo,
              time: r.raceTime,
              hasAltili: r.hasAltili,
              altiliNo: r.altiliNo,
              horses: r.horses.length,
            })),
          };
        }

        const cityInfo = TJK_CITIES[cityKey];
        const { data: bulletinData, error: bulletinError } = await supabase
          .from('bulletins')
          .upsert({
            race_date: dateStr,
            city_key: cityKey,
            city_name: cityInfo?.name || dynamicCityName,
            city_id: cityId,
          }, { onConflict: 'race_date,city_key' })
          .select('id')
          .single();

        if (bulletinError) throw bulletinError;
        const bulletinId = bulletinData.id;

        for (const race of bulletin.races) {
          const { data: raceData, error: raceError } = await supabase
            .from('races')
            .upsert({
              bulletin_id: bulletinId,
              race_no: race.raceNo,
              race_name: race.raceName,
              race_time: race.raceTime,
              race_type: race.raceType,
              has_altili: race.hasAltili,
              altili_no: race.altiliNo,
              mesafe: race.mesafe,
              kosul: race.kosul,
              eld: race.eld,
              ikramiye: race.ikramiye,
              ekuri: race.ekuri,
              has_cifte: race.hasCifte,
              has_ikili: race.hasIkili,
              has_sirali_ikili: race.hasSiraliIkili,
              has_plase: race.hasPlase,
              has_plase_ikili: race.hasPlaseIkili,
              has_uclu_bahis: race.hasUcluBahis,
              has_7li_ganyan: race.has7liGanyan,
              has_7li_plase: race.has7liPlase,
              has_3lu_ganyan: race.has3luGanyan,
            }, { onConflict: 'bulletin_id,race_no' })
            .select('id')
            .single();

          if (raceError) throw raceError;
          const raceId = raceData.id;

          for (const horse of race.horses) {
            await supabase
              .from('horses')
              .upsert({
                race_id: raceId,
                horse_no: horse.horseNo,
                horse_name: horse.horseName,
                jockey_name: horse.jockeyName,
                last_6_races: horse.last6Races,
              }, { onConflict: 'race_id,horse_no' });
          }
        }

        return { city: cityKey, status: 'ok', racesCount: bulletin.races.length, cityId };
      } catch (err) {
        return { city: cityKey, status: `error: ${err}`, racesCount: 0, cityId };
      }
    });

    const settled = await Promise.all(cityPromises);
    results.push(...settled);

    return NextResponse.json({
      success: true,
      date: dateStr,
      force,
      debug,
      citiesFound: todayCities.map(c => `${c.cityKey}(id=${c.cityId})`),
      results,
      timestamp: new Date().toISOString(),
    });
  } catch (error) {
    return NextResponse.json({ error: String(error) }, { status: 500 });
  }
}

